12	// MigrateStats reports what Migrate did in a single pass.
13	type MigrateStats struct {
14		// EventsExternalized is the number of beads whose inline events were
15		// moved to the .ddx/attachments/<id>/events.jsonl sidecar.
16		EventsExternalized int
17		// EventRecordsExternalized is the total number of individual event rows
18		// moved out of inline bead storage and into attachment sidecars.
19		EventRecordsExternalized int
20		// AttachmentsTouched is the number of per-bead attachment files written.
21		AttachmentsTouched int
22		// Archived is the number of closed beads moved from the active
23		// collection to beads-archive.
24		Archived int
25	}
26	
27	// Changed reports whether Migrate mutated on-disk state in this pass.
28	func (m MigrateStats) Changed() bool {
29		return m.EventsExternalized > 0 || m.Archived > 0
30	}
