32	const (
33		// LifecycleSchemaMarkerFile is written after the one-way lifecycle
34		// migration has converted legacy queue-driving labels into status-owned
35		// state. The startup gate added by a later bead can use this sentinel
36		// without scanning for historical transient metadata on every launch.
37		LifecycleSchemaMarkerFile    = "lifecycle-schema.json"
38		LifecycleSchemaMarkerVersion = 1
39	)
