41	// LifecycleMigrationStats reports what the one-way lifecycle migration did or
42	// would do. Target counts are row counts by post-migration persisted status.
43	type LifecycleMigrationStats struct {
44		LegacyNeedsHumanLabels                 int  `json:"legacy_needs_human_labels"`
45		LegacyNeedsInvestigationLabels         int  `json:"legacy_needs_investigation_labels"`
46		LegacyNeedsInvestigationPseudoStatuses int  `json:"legacy_needs_investigation_pseudo_statuses"`
47		LegacyNoChangesMetadataRows            int  `json:"legacy_no_changes_metadata_rows"`
48		ToProposed                             int  `json:"to_proposed"`
49		ToOpen                                 int  `json:"to_open"`
50		ToBlocked                              int  `json:"to_blocked"`
51		ToClosed                               int  `json:"to_closed"`
52		ToCancelled                            int  `json:"to_cancelled"`
53		RowsChanged                            int  `json:"rows_changed"`
54		SchemaMarkerMissing                    bool `json:"schema_marker_missing"`
55		MarkerWritten                          bool `json:"marker_written,omitempty"`
56		DryRun                                 bool `json:"dry_run,omitempty"`
57	}
