74	// LifecycleSchemaMarkerPath returns the marker file path under the store's
75	// .ddx directory.
76	func (s *Store) LifecycleSchemaMarkerPath() string {
77		return filepath.Join(s.Dir, LifecycleSchemaMarkerFile)
78	}
79	
80	// HasLifecycleSchemaMarker reports whether the lifecycle migration sentinel is
81	// present.
82	func (s *Store) HasLifecycleSchemaMarker() (bool, error) {
83		_, err := os.Stat(s.LifecycleSchemaMarkerPath())
84		if err == nil {
85			return true, nil
86		}
87		if os.IsNotExist(err) {
88			return false, nil
89		}
90		return false, err
91	}
