93	// WriteLifecycleSchemaMarker records the lifecycle migration sentinel.
94	func (s *Store) WriteLifecycleSchemaMarker(now time.Time) error {
95		if now.IsZero() {
96			now = time.Now().UTC()
97		}
98		if err := os.MkdirAll(s.Dir, 0o755); err != nil {
99			return fmt.Errorf("bead: lifecycle marker mkdir: %w", err)
100		}
101		payload := map[string]any{
102			"schema":     "bead-lifecycle",
103			"version":    LifecycleSchemaMarkerVersion,
104			"applied_at": now.UTC().Format(time.RFC3339),
105			"source":     "ddx bead migrate --lifecycle",
106		}
107		data, err := json.MarshalIndent(payload, "", "  ")
108		if err != nil {
109			return fmt.Errorf("bead: lifecycle marker marshal: %w", err)
110		}
111		data = append(data, '\n')
112		return writeAtomicFile(s.LifecycleSchemaMarkerPath(), data)
113	}
