115	// MigrateLifecycleDryRun reports the one-way lifecycle migration without
116	// mutating the tracker or marker.
117	func (s *Store) MigrateLifecycleDryRun() (LifecycleMigrationStats, error) {
118		return s.migrateLifecycle(false, time.Now().UTC())
