121	// MigrateLifecycle converts legacy lifecycle labels and pseudo-statuses into
122	// status-owned lifecycle state, then writes the lifecycle schema marker.
123	func (s *Store) MigrateLifecycle() (LifecycleMigrationStats, error) {
124		return s.migrateLifecycle(true, time.Now().UTC())
125	}
