127	func (s *Store) migrateLifecycle(apply bool, now time.Time) (LifecycleMigrationStats, error) {
128		var stats LifecycleMigrationStats
129		stats.DryRun = !apply
130		if s.Collection != DefaultCollection {
131			return stats, fmt.Errorf("bead: lifecycle migration only runs from the active %q collection (got %q)", DefaultCollection, s.Collection)
132		}
133		markerPresent, err := s.HasLifecycleSchemaMarker()
134		if err != nil {
135			return stats, fmt.Errorf("bead: lifecycle marker: %w", err)
136		}
137		stats.SchemaMarkerMissing = !markerPresent
138	
139		var plans []lifecycleMigrationPlan
140		err = s.WithLock(func() error {
141			beads, _, rerr := s.readAllLatestRaw()
142			if rerr != nil {
143				return rerr
144			}
145			plans = planLifecycleMigrations(beads, &stats)
146			if !apply {
147				return nil
148			}
149			for _, plan := range plans {
150				if err := applyLifecycleMigrationPlan(&beads[plan.index], plan, now); err != nil {
151					return err
152				}
153				if err := s.validateBead(&beads[plan.index]); err != nil {
154					return err
155				}
156			}
157			if len(plans) > 0 {
158				if err := s.WriteAll(beads); err != nil {
159					return err
160				}
161			}
162			return nil
163		})
164		if err != nil {
165			return stats, err
166		}
167		stats.RowsChanged = len(plans)
168		if apply && stats.SchemaMarkerMissing {
169			if err := s.WriteLifecycleSchemaMarker(now); err != nil {
170				return stats, err
171			}
172			stats.MarkerWritten = true
173		}
174		return stats, nil
175	}
