177	func planLifecycleMigrations(beads []Bead, stats *LifecycleMigrationStats) []lifecycleMigrationPlan {
178		var plans []lifecycleMigrationPlan
179		for i, b := range beads {
180			plan, ok := planLifecycleMigration(i, b)
181			if !ok {
182				continue
183			}
184			countLifecycleMigrationFacts(b, stats)
185			countLifecycleMigrationTarget(plan.targetStatus, stats)
186			plans = append(plans, plan)
187		}
188		return plans
189	}
190	
191	func planLifecycleMigration(index int, b Bead) (lifecycleMigrationPlan, bool) {
192		events := decodeBeadEvents(b.Extra["events"])
193		latest := latestLifecycleEvent(events)
194		legacyLabels := legacyLifecycleLabelsPresent(b)
195		legacyFields := noChangesFieldsPresent(b)
196		pseudoStatus := !IsCanonicalStatus(b.Status)
197		latestNeedsMigration := latest.Kind == "no_changes_needs_investigation" || latest.Kind == "no_changes_blocked"
198		needsMigration := pseudoStatus || len(legacyLabels) > 0 || len(legacyFields) > 0 || latestNeedsMigration || blockedMissingExternalReason(b)
199		if !needsMigration {
200			return lifecycleMigrationPlan{}, false
201		}
202	
203		target := canonicalLifecycleMigrationBaseStatus(b.Status)
204		reason := ""
205		externalReason := ""
206	
207		if isTerminalLifecycleStatus(target) {
208			reason = "terminal bead legacy lifecycle metadata archived as explanatory history"
209		} else if external, why := lifecycleMigrationExternalBlocker(b, latest); external {
210			target = StatusBlocked
211			externalReason = why
212			reason = "legacy lifecycle metadata represented an external recheckable blocker"
213		} else if lifecycleMigrationOperatorRequired(b, latest) {
214			target = StatusProposed
215			reason = "legacy lifecycle metadata required operator attention"
216		} else if target == StatusOpen {
217			target = StatusOpen
218			reason = "legacy lifecycle metadata was retryable autonomous work"
219		} else {
220			reason = "legacy lifecycle metadata removed without lifecycle status change"
221		}
222	
223		return lifecycleMigrationPlan{
224			index:                 index,
225			fromStatus:            b.Status,
226			targetStatus:          target,
227			reason:                reason,
228			externalBlockerReason: externalReason,
229			removeLabels:          legacyLabels,
230			clearFields:           legacyFields,
231		}, true
232	}
