234	func countLifecycleMigrationFacts(b Bead, stats *LifecycleMigrationStats) {
235		if hasLabel(b, LabelNeedsHuman) {
236			stats.LegacyNeedsHumanLabels++
237		}
238		if hasLabel(b, LabelNeedsInvestigation) {
239			stats.LegacyNeedsInvestigationLabels++
240		}
241		if b.Status == "needs_investigation" {
242			stats.LegacyNeedsInvestigationPseudoStatuses++
243		}
244		if len(noChangesFieldsPresent(b)) > 0 {
245			stats.LegacyNoChangesMetadataRows++
246		}
247	}
