249	func countLifecycleMigrationTarget(status string, stats *LifecycleMigrationStats) {
250		switch status {
251		case StatusProposed:
252			stats.ToProposed++
253		case StatusOpen:
254			stats.ToOpen++
255		case StatusBlocked:
256			stats.ToBlocked++
257		case StatusClosed:
258			stats.ToClosed++
259		case StatusCancelled:
260			stats.ToCancelled++
261		}
262	}
