264	func applyLifecycleMigrationPlan(b *Bead, plan lifecycleMigrationPlan, now time.Time) error {
265		if b.Extra == nil {
266			b.Extra = make(map[string]any)
267		}
268		fromForTransition := b.Status
269		if !IsCanonicalStatus(fromForTransition) {
270			b.Status = StatusOpen
271			fromForTransition = StatusOpen
272		}
273		opts := LifecycleTransitionOptions{
274			OperatorRequired:      plan.targetStatus == StatusProposed,
275			ExternalBlockerReason: plan.externalBlockerReason,
276			Reason:                plan.reason,
277			Actor:                 "ddx",
278			Source:                "ddx bead migrate --lifecycle",
279		}
280		if b.Status != plan.targetStatus {
281			if err := transitionLifecycleInPlace(b, plan.targetStatus, opts); err != nil {
282				return err
283			}
284		} else if plan.targetStatus == StatusBlocked {
285			applyLifecycleTransitionMetadata(b, StatusBlocked, StatusBlocked, opts)
286		}
287		if fromForTransition == StatusInProgress && b.Status != StatusInProgress {
288			clearClaimMetadata(b)
289		}
290	
291		for _, label := range plan.removeLabels {
292			removeLabel(b, label)
293		}
294		for _, key := range plan.clearFields {
295			delete(b.Extra, key)
296		}
297		if plan.targetStatus != StatusBlocked {
298			delete(b.Extra, ExtraLifecycleExternalBlockerReason)
299		}
300		if plan.targetStatus == StatusProposed {
301			meta := GetNeedsHumanMeta(*b)
302			if strings.TrimSpace(meta.Reason) == "" {
303				meta.Reason = plan.reason
304			}
305			if strings.TrimSpace(meta.Since) == "" {
306				meta.Since = now.UTC().Format(time.RFC3339)
307			}
308			if strings.TrimSpace(meta.Source) == "" {
309				meta.Source = "ddx bead migrate --lifecycle"
310			}
311			if strings.TrimSpace(meta.SuggestedAction) == "" {
312				meta.SuggestedAction = "review and accept, split, block, or cancel this proposed work"
313			}
314			SetNeedsHumanMeta(b, meta)
315		}
316		b.Extra["lifecycle-migrated-at"] = now.UTC().Format(time.RFC3339)
317		b.Extra["lifecycle-migrated-from-status"] = plan.fromStatus
318		b.Extra["lifecycle-migrated-to-status"] = plan.targetStatus
319		appendInlineEvent(b, BeadEvent{
320			Kind:      "lifecycle_migrated",
321			Summary:   plan.reason,
322			Body:      lifecycleMigrationEventBody(plan),
323			Actor:     "ddx",
324			Source:    "ddx bead migrate --lifecycle",
325			CreatedAt: now.UTC(),
326		})
327		return nil
328	}
