330	func lifecycleMigrationEventBody(plan lifecycleMigrationPlan) string {
331		var parts []string
332		parts = append(parts, "from_status="+plan.fromStatus)
333		parts = append(parts, "to_status="+plan.targetStatus)
334		if plan.externalBlockerReason != "" {
335			parts = append(parts, "external_blocker_reason="+plan.externalBlockerReason)
336		}
337		if len(plan.removeLabels) > 0 {
338			parts = append(parts, "removed_labels="+strings.Join(plan.removeLabels, ","))
339		}
340		if len(plan.clearFields) > 0 {
341			parts = append(parts, "cleared_fields="+strings.Join(plan.clearFields, ","))
342		}
343		return strings.Join(parts, "\n")
344	}
