346	func legacyLifecycleLabelsPresent(b Bead) []string {
347		var labels []string
348		for _, label := range []string{
349			LabelNeedsHuman,
350			LabelNeedsInvestigation,
351			LabelNoChangesUnverified,
352			LabelNoChangesUnjustified,
353		} {
354			if hasLabel(b, label) {
355				labels = append(labels, label)
356			}
357		}
358		return labels
