361	func canonicalLifecycleMigrationBaseStatus(status string) string {
362		if IsCanonicalStatus(status) {
363			return status
364		}
365		switch status {
366		case "needs_human", "needs_investigation":
367			return StatusOpen
368		default:
369			return StatusOpen
370		}
371	}
