381	func lifecycleMigrationExternalBlocker(b Bead, latest BeadEvent) (bool, string) {
382		if b.Status == StatusBlocked {
383			return true, firstNonEmpty(
384				extraStringVal(b.Extra, ExtraLifecycleExternalBlockerReason),
385				extraStringVal(b.Extra, ExtraLastDetail),
386				latest.Body,
387				"legacy blocked status",
388			)
389		}
390		if latest.Kind == "no_changes_blocked" {
391			return true, firstNonEmpty(latest.Body, latest.Summary, "legacy no_changes blocked outcome")
392		}
393		lastStatus := strings.ToLower(strings.TrimSpace(extraStringVal(b.Extra, ExtraLastStatus)))
394		detail := firstNonEmpty(extraStringVal(b.Extra, ExtraLastDetail), latest.Body)
395		if lastStatus == "blocked" || lastStatus == "external_blocked" {
396			return true, firstNonEmpty(detail, "legacy blocked no_changes outcome")
397		}
398		lower := strings.ToLower(detail)
399		for _, marker := range []string{
400			"external blocker",
401			"blocked on upstream",
402			"blocked by upstream",
403			"waiting on upstream",
404			"requires upstream",
405			"blocked by external",
406		} {
407			if strings.Contains(lower, marker) {
408				return true, firstNonEmpty(detail, marker)
409			}
410		}
411		return false, ""
412	}
