414	func lifecycleMigrationOperatorRequired(b Bead, latest BeadEvent) bool {
415		if hasLabel(b, LabelNeedsHuman) || b.Status == "needs_human" {
416			return true
417		}
418		if hasAnyExtra(b, ExtraNeedsHumanReason, ExtraNeedsHumanSuggestedAction, ExtraNeedsHumanSummary) {
419			return true
420		}
421		text := strings.ToLower(strings.Join([]string{
422			extraStringVal(b.Extra, ExtraLastDetail),
423			latest.Body,
424			latest.Summary,
425		}, "\n"))
426		if latest.Kind == "no_changes_needs_investigation" && !containsSmartRunnableMarker(text) {
427			return true
428		}
429		for _, marker := range []string{
430			"operator",
431			"human",
432			"manual",
433			"approval",
434			"approve",
435			"clarification",
436			"decision",
437			"non-scope",
438			"not in scope",
439		} {
440			if strings.Contains(text, marker) {
441				return true
442			}
443		}
444		return false
445	}
