485	// Migrate splits the existing active beads collection into the modern
486	// layout: closed beads' inline events are externalized to the attachment
487	// store (per ADR-004), and eligible closed beads are moved to the
488	// beads-archive partner (per TD-027). It is idempotent — a second call
489	// with no further changes is a no-op.
490	//
491	// Migrate uses a permissive archival policy (MinAge=0, MinActiveCount=0)
492	// so it drains the historical backlog. Routine archival (after Close)
493	// uses the policy assembled by `ddx bead archive` from its flag set.
494	func (s *Store) Migrate() (MigrateStats, error) {
495		return s.ArchiveWithEvents(migratePolicy())
496	}
497	
498	// MigrateDryRun reports what Migrate would do without mutating disk. It uses
499	// the same eligibility logic as Migrate (Statuses=[closed], no MinAge floor,
500	// preserve_dependencies retention).
501	func (s *Store) MigrateDryRun() (MigrateStats, error) {
502		var stats MigrateStats
503		if s.Collection != DefaultCollection {
504			return stats, fmt.Errorf("bead: migrate dry-run only runs from the active %q collection (got %q)", DefaultCollection, s.Collection)
505		}
506		policy := migratePolicy()
507	
508		var beads []Bead
509		err := s.WithLock(func() error {
510			all, _, rerr := s.readAllLatestRaw()
511			if rerr != nil {
512				return rerr
513			}
514			beads = all
515			return nil
516		})
517		if err != nil {
518			return stats, err
519		}
520	
521		referenced := make(map[string]bool)
522		for _, b := range beads {
523			if b.Status == StatusClosed {
524				continue
525			}
526			for _, dep := range b.DepIDs() {
527				referenced[dep] = true
528			}
529		}
530	
531		for _, b := range beads {
532			if !containsString(policy.Statuses, b.Status) {
533				continue
534			}
535			if hasInlineEvents(&b) {
536				stats.EventsExternalized++
537				stats.EventRecordsExternalized += inlineEventCount(&b)
538				stats.AttachmentsTouched++
539			}
540			if referenced[b.ID] {
541				continue
542			}
543			ts := b.UpdatedAt
544			if raw, ok := b.Extra["closed_at"].(string); ok {
545				if parsed, perr := time.Parse(time.RFC3339, raw); perr == nil {
546					ts = parsed
547				}
548			}
549			if policy.MinAge > 0 && time.Now().UTC().Sub(ts) < policy.MinAge {
550				continue
551			}
552			stats.Archived++
553		}
554		return stats, nil
555	}
556	
557	func migratePolicy() ArchivePolicy {
558		return ArchivePolicy{
559			Statuses:       []string{StatusClosed},
560			MinAge:         0,
561			MinActiveCount: 0,
562			BatchSize:      0,
563		}
564	}
565	
566	// ArchiveWithEvents externalizes inline events for every bead whose status
567	// matches policy.Statuses, then archives eligible beads under the same
568	// policy. This is the operator-facing path used by `ddx bead archive` and
569	// the internal path used by `ddx bead migrate`.
570	func (s *Store) ArchiveWithEvents(policy ArchivePolicy) (MigrateStats, error) {
571		var stats MigrateStats
572		if s.Collection != DefaultCollection {
573			return stats, fmt.Errorf("bead: archive only runs from the active %q collection (got %q)", DefaultCollection, s.Collection)
574		}
575	
576		// Step 1: externalize inline events on every eligible-status bead under
577		// the active store's lock. This shrinks the row size before we try to
578		// archive, so the archive partner inherits already-thin rows.
579		err := s.WithLock(func() error {
580			beads, _, rerr := s.readAllLatestRaw()
581			if rerr != nil {
582				return rerr
583			}
584			dirty := false
585			for i := range beads {
586				if !containsString(policy.Statuses, beads[i].Status) {
587					continue
588				}
589				if !hasInlineEvents(&beads[i]) {
590					continue
591				}
592				stats.EventsExternalized++
593				stats.EventRecordsExternalized += inlineEventCount(&beads[i])
594				stats.AttachmentsTouched++
595				if eerr := s.externalizeEventsInPlace(&beads[i]); eerr != nil {
596					return eerr
597				}
598				dirty = true
599			}
600			if !dirty {
601				return nil
602			}
603			return s.WriteAll(beads)
604		})
605		if err != nil {
606			return stats, fmt.Errorf("bead: archive externalize: %w", err)
607		}
608	
609		moved, err := s.Archive(policy)
610		if err != nil {
611			return stats, fmt.Errorf("bead: archive: %w", err)
612		}
613		stats.Archived = len(moved)
614		return stats, nil
615	}
