617	// MigrateAxonStats reports what MigrateToAxon copied in a single pass.
618	type MigrateAxonStats struct {
619		// BeadsMigrated is the total number of distinct bead IDs written into
620		// the axon backend (active + archive, deduped on ID).
621		BeadsMigrated int
622		// EventsMigrated is the total number of inline events written into the
623		// ddx_bead_events collection. Externalized events (referenced via
624		// Extra[events_attachment]) are not counted because they are not
625		// rewritten by the migration — the attachment file remains canonical.
626		EventsMigrated int
627	}
628	
629	// MigrateToAxon reads beads from the JSONL active collection
630	// (.ddx/beads.jsonl) and the JSONL archive partner
631	// (.ddx/beads-archive.jsonl) rooted under s.Dir and writes them losslessly
632	// into the axon backend (.ddx/axon/). Source files are not modified.
633	//
634	// Reads always go through fresh JSONL backends regardless of s.backend so
635	// the migration is deterministic and not affected by the operator's
636	// configured backend (e.g. an axon-misconfigured store still migrates from
637	// the on-disk JSONL files). Active wins on duplicate IDs.
638	//
639	// Idempotent: AxonBackend.WriteAll overwrites both collection files in
640	// temp+rename style, so re-running on the same source state produces an
641	// identical axon snapshot with no duplicates.
642	func (s *Store) MigrateToAxon() (MigrateAxonStats, error) {
643		var stats MigrateAxonStats
644	
645		activeSpec := DefaultRegistry().Resolve(DefaultCollection)
646		activeFile, activeLock := activeSpec.PathsUnder(s.Dir)
647		activeBackend := NewJSONLBackend(s.Dir, activeFile, activeLock, s.LockWait)
648	
649		archiveSpec := DefaultRegistry().Resolve(BeadsArchiveCollection)
650		archiveFile, archiveLock := archiveSpec.PathsUnder(s.Dir)
651		archiveBackend := NewJSONLBackend(s.Dir, archiveFile, archiveLock, s.LockWait)
652	
653		activeBeads, err := activeBackend.ReadAll()
654		if err != nil {
655			return stats, fmt.Errorf("bead: migrate-to-axon read active: %w", err)
656		}
657		archiveBeads, err := archiveBackend.ReadAll()
658		if err != nil {
659			return stats, fmt.Errorf("bead: migrate-to-axon read archive: %w", err)
660		}
661	
662		seen := make(map[string]bool, len(activeBeads))
663		merged := make([]Bead, 0, len(activeBeads)+len(archiveBeads))
664		for _, b := range activeBeads {
665			seen[b.ID] = true
666			merged = append(merged, b)
667		}
668		for _, b := range archiveBeads {
669			if seen[b.ID] {
670				continue
671			}
672			seen[b.ID] = true
673			merged = append(merged, b)
674		}
675	
676		for i := range merged {
677			stats.BeadsMigrated++
678			if hasInlineEvents(&merged[i]) {
679				stats.EventsMigrated += len(decodeBeadEvents(merged[i].Extra["events"]))
680			}
681		}
682	
683		axon := NewAxonBackend(s.Dir, s.LockWait)
684		if err := axon.Init(); err != nil {
685			return stats, fmt.Errorf("bead: migrate-to-axon init: %w", err)
686		}
687		if err := axon.WithLock(func() error {
688			return axon.WriteAll(merged)
689		}); err != nil {
690			return stats, fmt.Errorf("bead: migrate-to-axon write: %w", err)
691		}
692		return stats, nil
693	}
694	
695	// hasInlineEvents reports whether a bead carries any inline events that
696	// can still be externalized. An empty array counts as "no inline events"
697	// so a second migrate pass on an already-externalized bead is a no-op.
698	func hasInlineEvents(b *Bead) bool {
699		if b == nil || b.Extra == nil {
700			return false
701		}
702		raw, ok := b.Extra["events"]
703		if !ok {
704			return false
705		}
706		return len(decodeBeadEvents(raw)) > 0
707	}
708	
709	func inlineEventCount(b *Bead) int {
710		if b == nil || b.Extra == nil {
711			return 0
712		}
713		raw, ok := b.Extra["events"]
714		if !ok {
715			return 0
716		}
717		return len(decodeBeadEvents(raw))
718	}
