116	// ReconcileLifecycleMetadata returns conservative repairs for stale
117	// no_changes management fields. With Apply=false it is a dry run; with
118	// Apply=true it mutates through the Store API and appends reconciliation
119	// evidence.
120	func (s *Store) ReconcileLifecycleMetadata(opts ReconcileOptions) ([]ReconcilePlan, error) {
121		if opts.Now.IsZero() {
122			opts.Now = time.Now().UTC()
123		}
124		beads, err := s.ReadAll(context.Background())
125		if err != nil {
126			return nil, err
127		}
128		childrenByParent := make(map[string]int)
129		nonTerminalChildrenByParent := make(map[string]int)
130		closedChildrenByParent := make(map[string]int)
131		idFilter := make(map[string]bool, len(opts.IDs))
132		for _, id := range opts.IDs {
133			if strings.TrimSpace(id) != "" {
134				idFilter[strings.TrimSpace(id)] = true
135			}
136		}
137		for _, b := range beads {
138			if b.Parent != "" {
139				childrenByParent[b.Parent]++
140				if b.Status != StatusClosed && b.Status != StatusCancelled {
141					nonTerminalChildrenByParent[b.Parent]++
142				}
143				if b.Status == StatusClosed {
144					closedChildrenByParent[b.Parent]++
145				}
146			}
147		}
148	
149		var plans []ReconcilePlan
150		for _, b := range beads {
151			if len(idFilter) > 0 && !idFilter[b.ID] {
152				continue
153			}
154			events, _ := s.eventsForBead(&b)
155			if p, ok := planLifecycleReconcile(b, events, childrenByParent[b.ID], nonTerminalChildrenByParent[b.ID], closedChildrenByParent[b.ID], opts.Now); ok {
156				if opts.Apply {
157					if err := s.applyReconcilePlan(p); err != nil {
158						return plans, err
159					}
160					p.Applied = true
161				}
162				plans = append(plans, p)
163			}
164		}
165		return plans, nil
166	}
