168	func planLifecycleReconcile(b Bead, events []BeadEvent, childCount, nonTerminalChildCount, closedChildCount int, now time.Time) (ReconcilePlan, bool) {
169		p := ReconcilePlan{
170			BeadID:        b.ID,
171			CurrentFields: currentLifecycleFields(b),
172		}
173		latest := latestLifecycleEvent(events)
174	
175		if b.Status == StatusClosed && hasClosedNoChangesResidue(b) {
176			p.Reason = "closed bead has stale no_changes lifecycle metadata"
177			p.ClearFields = noChangesFieldsPresent(b)
178			p.RemoveLabels = noChangesLabelsPresent(b)
179			return p, len(p.ClearFields) > 0 || len(p.RemoveLabels) > 0
180		}
181	
182		if isSuccessEvent(latest) && hasNoChangesResidue(b) {
183			p.Reason = "latest terminal success supersedes stale no_changes lifecycle metadata"
184			p.ClearFields = noChangesFieldsPresent(b)
185			p.RemoveLabels = noChangesLabelsPresent(b)
186			return p, len(p.ClearFields) > 0 || len(p.RemoveLabels) > 0
187		}
188	
189		if latest.Kind == "no_changes_verified" && b.Status != StatusClosed {
190			p.Reason = "verified no_changes evidence closes as already_satisfied"
191			p.ClearFields = noChangesFieldsPresent(b)
192			p.RemoveLabels = noChangesLabelsPresent(b)
193			p.TargetStatus = StatusClosed
194			p.CloseSatisfied = true
195			return p, true
196		}
197	
198		if isExpiredRetryAfter(b, now) {
199			p.Reason = "expired retry-after metadata no longer blocks execution"
200			p.ClearFields = []string{ExtraRetryAfter}
201			return p, true
202		}
203	
204		if isEpicBead(b) && childCount > 0 && nonTerminalChildCount == 0 && b.Status != StatusClosed && b.Status != StatusCancelled {
205			if closedChildCount == 0 {
206				p.Reason = "auto-cancel epic: all children cancelled, no work completed"
207				p.TargetStatus = StatusCancelled
208				p.CloseSatisfied = false
209				return p, true
210			}
211			p.Reason = "auto-close epic: all children reached terminal state"
212			p.TargetStatus = StatusClosed
213			p.CloseSatisfied = true
214			return p, true
215		}
216	
217		if isContainerBead(b, childCount) && noChangesCount(b) > 0 {
218			if b.Extra != nil {
219				if eligible, ok := b.Extra[ExtraExecutionElig].(bool); ok && !eligible {
220					return ReconcilePlan{}, false
221				}
222			}
223			p.Reason = "parent/epic work is owned by child beads"
224			p.SetFields = map[string]any{
225				ExtraExecutionElig:   false,
226				ExtraExecutionReason: "parent/epic container; execute child beads first",
227			}
228			return p, true
229		}
230	
231		return ReconcilePlan{}, false
232	}
