234	func (s *Store) applyReconcilePlan(p ReconcilePlan) error {
235		mutate := func(b *Bead) error {
236			if b.Extra == nil {
237				b.Extra = make(map[string]any)
238			}
239			for _, key := range p.ClearFields {
240				delete(b.Extra, key)
241			}
242			for key, value := range p.SetFields {
243				b.Extra[key] = value
244			}
245			for _, label := range p.RemoveLabels {
246				removeLabel(b, label)
247			}
248			for _, label := range p.AddLabels {
249				addLabel(b, label)
250			}
251			addLabel(b, LabelReconciledNoChangesState)
252			appendInlineEvent(b, BeadEvent{
253				Kind:      "lifecycle_reconciled",
254				Summary:   p.Reason,
255				Actor:     "ddx",
256				Source:    "ddx bead reconcile",
257				CreatedAt: time.Now().UTC(),
258			})
259			if strings.HasPrefix(p.Reason, "auto-close epic:") || strings.HasPrefix(p.Reason, "auto-cancel epic:") {
260				event := BeadEvent{
261					Kind:      "epic_auto_close",
262					Actor:     "ddx",
263					Source:    "ddx bead reconcile",
264					CreatedAt: time.Now().UTC(),
265				}
266				if p.TargetStatus == StatusCancelled {
267					event.Summary = "auto-cancelled: all children cancelled, no work completed"
268					event.Body = "closed_because: all_children_cancelled"
269				} else {
270					event.Summary = "auto-closed: all children reached terminal state"
271					event.Body = "closed_because: all_children_terminal"
272				}
273				appendInlineEvent(b, event)
274			}
275			return nil
276		}
277		var err error
278		if p.TargetStatus != "" {
279			// TD-031 §3.1: reconcile terminal transitions are meta-transitions that
280			// intentionally bypass ClosureGate — the bead has no execution session and
281			// no closing_commit_sha of its own. The bypass is safe because every
282			// transitive dependency is terminal, so the parent's transition inherits
283			// evidence by reference through dependency edges.
284			err = s.UpdateWithLifecycleStatus(p.BeadID, p.TargetStatus, LifecycleTransitionOptions{
285				ManualClose: true,
286				Reason:      p.Reason,
287				Actor:       "ddx",
288				Source:      "ddx bead reconcile",
289			}, mutate)
290		} else {
291			err = s.Update(context.Background(), p.BeadID, func(b *Bead) {
292				_ = mutate(b)
293			})
