33	// ExportTo writes all beads as JSONL to the given writer.
34	//
35	// For interchange compatibility with bd/br, externalized event histories are
36	// inlined back into the row's "events" array on the way out (the attachment
37	// ref itself is also dropped so importers don't see a dangling pointer).
38	// The on-disk row is unchanged — this is a transient mutation on the copied
39	// Bead value before marshaling.
40	//
41	// When called on the active collection, archived beads from the
42	// beads-archive partner are also streamed inline so a single export carries
43	// the full corpus. Each archived bead's externalized events are loaded from
44	// the active store's attachment dir (where Migrate writes them) before
45	// emission.
46	func (s *Store) ExportTo(w io.Writer) error {
47		beads, err := s.ReadAll(context.Background())
48		if err != nil {
49			return err
50		}
51		seen := make(map[string]bool, len(beads))
52		for _, b := range beads {
53			seen[b.ID] = true
54			if hasEventsAttachment(&b) {
55				if err := s.inlineEventsInPlace(&b); err != nil {
56					return fmt.Errorf("bead: export inline events: %w", err)
57				}
58			}
59			data, err := marshalBead(b)
60			if err != nil {
61				return fmt.Errorf("bead: export marshal: %w", err)
62			}
63			if _, err := fmt.Fprintf(w, "%s\n", data); err != nil {
64				return fmt.Errorf("bead: export write: %w", err)
65			}
66		}
67	
68		if s.Collection != DefaultCollection {
69			return nil
70		}
71		archive := s.archivePartner()
72		archived, aerr := archive.ReadAll(context.Background())
73		if aerr != nil {
74			// Treat a missing/unreadable archive partner as empty — the
75			// active collection is still a valid export.
76			return nil
77		}
78		for _, b := range archived {
79			if seen[b.ID] {
80				continue
81			}
82			if hasEventsAttachment(&b) {
83				// Attachments live under the active store's .ddx/attachments
84				// dir even after the bead moves to the archive (Migrate
85				// writes them there before archival). Use s, not archive,
86				// to resolve the sidecar path.
87				if err := s.inlineEventsInPlace(&b); err != nil {
88					return fmt.Errorf("bead: export inline events: %w", err)
89				}
90			}
91			data, err := marshalBead(b)
92			if err != nil {
93				return fmt.Errorf("bead: export marshal: %w", err)
94			}
95			if _, err := fmt.Fprintf(w, "%s\n", data); err != nil {
96				return fmt.Errorf("bead: export write: %w", err)
97			}
98		}
99		return nil
100	}
