107	// DetectLifecycleMigrationRequired reports whether the active JSONL bead queue still
108	// contains unmigrated lifecycle routing state.
109	//
110	// The detector is intentionally cheap:
111	//   - non-default collections and non-JSONL backends are treated as
112	//     migration-not-required because they do not represent the active
113	//     beads.jsonl queue;
114	//   - a missing active beads.jsonl file is also treated as not required
115	//     rather than as an error;
116	//   - the lifecycle schema marker is reported when present/absent, but
117	//     marker absence alone does not fail the gate unless legacy rows are
118	//     also present.
119	func (s *Store) DetectLifecycleMigrationRequired() (LifecycleMigrationGateStatus, error) {
120		var report LifecycleMigrationGateStatus
121		if s == nil || s.Collection != DefaultCollection || s.backend != nil {
122			report.Code = LifecycleMigrationGateCodeNotRequired
123			return report, nil
124		}
125	
126		if _, err := os.Stat(s.File); err != nil {
127			if os.IsNotExist(err) {
128				report.Code = LifecycleMigrationGateCodeNotRequired
129				return report, nil
130			}
131			return report, fmt.Errorf("bead: lifecycle gate stat %s: %w", s.File, err)
132		}
133	
134		report.QueuePresent = true
135		markerPresent, markerVersion, err := s.detectLifecycleSchemaMarker()
136		if err != nil {
137			return report, fmt.Errorf("bead: lifecycle gate marker: %w", err)
138		}
139		report.SchemaMarkerMissing = !markerPresent
140		report.SchemaMarkerVersion = markerVersion
141		report.SchemaMarkerOld = markerPresent && markerVersion < LifecycleSchemaMarkerVersion
142	
143		beads, _, err := s.readAllLatestRaw()
144		if err != nil {
145			return report, fmt.Errorf("bead: lifecycle gate read %s: %w", s.File, err)
146		}
147		if len(beads) == 0 && !report.Required() {
148			report.Code = LifecycleMigrationGateCodeNotRequired
149			return report, nil
150		}
151	
152		sampleSeen := make(map[string]struct{}, lifecycleMigrationGateSampleLimit)
153		addSample := func(id string) {
154			if id == "" {
155				return
156			}
157			if len(report.SampleBeadIDs) >= lifecycleMigrationGateSampleLimit {
158				return
159			}
160			if _, ok := sampleSeen[id]; ok {
161				return
162			}
163			sampleSeen[id] = struct{}{}
164			report.SampleBeadIDs = append(report.SampleBeadIDs, id)
165		}
166	
167		for _, b := range beads {
168			legacy := false
169			if hasLabel(b, LabelNeedsHuman) {
170				report.LegacyNeedsHumanLabels++
171				legacy = true
172			}
173			if hasLabel(b, LabelNeedsInvestigation) {
174				report.LegacyNeedsInvestigationLabels++
175				legacy = true
176			}
177			if b.Status == "needs_investigation" {
178				report.LegacyNeedsInvestigationStatuses++
179				legacy = true
180			}
181			if len(noChangesFieldsPresent(b)) > 0 {
182				report.LegacyNoChangesMetadataRows++
183				legacy = true
184			}
185			if legacy {
186				addSample(b.ID)
187			}
188		}
189	
190		if report.Required() {
191			report.Code = LifecycleMigrationGateCodeRequired
192		} else {
193			report.Code = LifecycleMigrationGateCodeNotRequired
194		}
195	
196		return report, nil
197	}
